mapper.update:
UPDATE CAMPAIGN_MST SET
    CAMP_NM = #{CAMP_NM}, SURV_GB = #{SURV_GB}, ACTDATE = #{ACTDATE}, REMARK = #{REMARK},
    STATUS = #{STATUS}, START_MENT = #{START_MENT}, END_MENT = #{END_MENT}, UPDTIME = GETDATE(), UPDEMP = #{UPDEMP}
WHERE CMPYCD = #{CMPYCD} AND CAMP_NO = #{CAMP_NO}

mapper.select:
SELECT A.CALL_SEQ, A.CMPYCD, A.CAMP_NO, A.SURV_GB, A.CUST_NM, A.EMAIL, A.TEL_NO, A.STATUS, ISNULL(A.RSLT_CD,'') AS RSLT_CD, ISNULL(B.CODENM, '미처리') AS RSLT_NM, A.USERID, A.EXT_DATA, R.RSLT_NO, FORMAT(R.START_DTIME, 'YYYY-MM-DD HH:MM:SS') AS START_DTIME, FORMAT(R.END_DTIME, 'YYYY-MM-DD HH:MM:SS') AS END_DTIME, R.REMARK, R.REC_FILE, R.MEDIA_TYPE, R.CHAT_LOG, U.USERNM AS CONSULTNM FROM CAMPAIGN_CALL_LIST A LEFT OUTER JOIN HABA900T_TBL B ON B.CDTYPE = '920' AND A.RSLT_CD = B.CODECD OUTER APPLY ( SELECT TOP 1 RS.RSLT_NO, RS.START_DTIME, RS.END_DTIME, RS.REMARK, RS.REC_FILE, RS.MEDIA_TYPE, RS.CHAT_LOG, RS.USERID, RS.CMPYCD FROM CAMPAIGN_RSLT_MST RS WHERE RS.CMPYCD = A.CMPYCD AND RS.CALL_SEQ = A.CALL_SEQ ORDER BY RS.RSLT_NO DESC ) R LEFT OUTER JOIN HABA920T_TBL U ON R.USERID = U.USERID AND R.CMPYCD = U.CMPYCD WHERE A.CMPYCD = #{CMPYCD} AND A.CAMP_NO = #{CAMP_NO} AND a.call_seq = #{CALL_SEQ} AND a.rslt_cd = #{FILTER}
AND (A.CUST_NM LIKE '%' + #{KEYWORD} + '%' OR A.TEL_NO LIKE '%' + #{KEYWORD} + '%')
ORDER BY A.CALL_SEQ DESC

